export const addObserver: unique symbol = Symbol('addObserver');
export const removeObserver: unique symbol = Symbol('removeObserver');
export const hasObserver: unique symbol = Symbol('getObservers');
export const swapObserver: unique symbol = Symbol('swapObserver');
export const isProxy: unique symbol = Symbol('isProxy');
export const getTarget: unique symbol = Symbol('getTarget');

type AddObserverCallback = (key?: string) => void;
type AddObserver = (host: HTMLElement, callback: AddObserverCallback) => void;
type RemoveObserver = (host: HTMLElement) => void;

const arrayMutate = ['fill', 'pop', 'push', 'reverse', 'shift', 'sort', 'splice', 'unshift'];
const arrayRead = ['forEach', 'slice', 'some', 'map', 'indexOf', 'lastIndexOf', 'width'];

// key = obj                - observed object
// value = Map
//   key = host             - web component
//   value = Map
//     key = element        - forEach container or binding
//     value = callback[]
type ElementMap = Map<Element, any[]>;
type HostMap = Map<Element, ElementMap>;
const observers = new Map<any, HostMap>();
//@ts-ignore
window.observers = observers;

type IsAny<T> = unknown extends T & string ? true : false;

type ExtrasArray<T> = {
  [addObserver]: AddObserver;
  [removeObserver]: RemoveObserver;
  [isProxy]: boolean;
} & Array<T extends (infer U)[] ? Partial<U> : object>;

type Extras = {
  [addObserver]: AddObserver;
  [removeObserver]: RemoveObserver;
  [isProxy]: boolean;
};

// Short-circuit any or this is infinite
type RecursiveProxy<T> = IsAny<T> extends true
  ? any
  : T extends Array<any>
  ? ExtrasArray<T> & {
    [P in keyof T]: IsAny<T[P]> extends true ? any : RecursiveProxy<T[P]>
  }
  : {
    [P in keyof T]: IsAny<T[P]> extends true
    ? any
    : T[P] extends Array<any>
    ? RecursiveProxy<T[P]>
    : T[P]
  } & Extras;

export function createProxy<T>(obj: T): RecursiveProxy<T> {
  return new Proxy(obj as any, {
    get(target: any, prop: string | symbol): any {
      if (typeof prop === 'symbol') {
        switch (prop) {
          case isProxy:
            return true;
          case getTarget:
            return target;
          case hasObserver:
            return (host: HTMLElement) => {
              const hosts = observers.get(obj);
              return hosts?.has(host);
            };
          case swapObserver:
            return (host: HTMLElement, newObj: any) => {
              const hosts = observers.get(obj);
              if (hosts) {
                const elements = hosts.get(host);
                if (elements) {
                  elements.forEach((callbacks: any[], element) => {
                    if (callbacks) {
                      const hostsNew = observers.get(newObj);
                      if (hostsNew) {
                        const elementsNew = hostsNew.get(host);
                        if (elementsNew) {
                          elementsNew.set(element, callbacks);
                        } else {
                          hostsNew.set(
                            host,
                            new Map([[
                              element,
                              callbacks
                            ]])
                          );
                        }
                      } else {
                        observers.set(
                          newObj,
                          new Map([[
                            host,
                            new Map([[
                              element,
                              callbacks
                            ]])
                          ]])
                        );
                      }
                    } else {
                      throw new Error('Unreachable');
                    }
                    elements.delete(element);
                    callbacks.forEach((callback: any) => {
                      callback(null, Mutation.swap, [newObj]);
                    });
                  });
                }
              }
            }
          case addObserver:
            return (element: HTMLElement, callback: AddObserverCallback) => {
              const host = (element.getRootNode() as ShadowRoot).host;
              const hosts = observers.get(obj);
              if (hosts) {
                const elements = hosts.get(host);
                if (elements) {
                  const callbacks = elements.get(element);
                  if (callbacks) {
                    callbacks.push(callback);
                  } else {
                    elements.set(element, [callback]);
                  }
                } else {
                  hosts.set(
                    host,
                    new Map([[
                      element, [callback]
                    ]])
                  );
                }
              } else {
                observers.set(
                  obj,
                  new Map([[
                    host,
                    new Map([[
                      element, [callback]
                    ]])
                  ]])
                );
              }
            };
          case removeObserver:
            return (element: HTMLElement) => {
              const host = (element.getRootNode() as ShadowRoot).host;
              const hosts = observers.get(obj);
              if (hosts) {
                hosts.delete(host);
                if (hosts.size === 0) {
                  observers.delete(obj);
                }
              }
            };
          case Symbol.toPrimitive:
          case Symbol.toStringTag:
            return Reflect.get(target, prop);
        }
        throw new Error('Unsupported symbol');
      }
      if (prop in target) {
        if (!Number.isNaN(Number(prop))) {
          if (typeof target[prop] === 'object') {
            return createProxy(target[prop]);
          }
          return target[prop];
        }
        if (prop === 'copyWithin') {
          throw new Error('Unsupported array method copyWithin');
        }
        if (arrayMutate.includes(prop)) {
          if (observers.has(target)) {
            return function () {
              const result = Array.prototype[prop as any].apply(target, arguments);
              const hosts = observers.get(target);
              hosts?.forEach((elements) => {
                elements.forEach((callbacks: any) => {
                  callbacks.forEach((callback: any) => {
                    callback(target, prop, arguments);
                  });
                });
              });
              return result;
            }
          }
          return Reflect.get(target, prop);
        }
        if (target[prop] instanceof Array) {
          return createProxy(target[prop]);
        }
        // nested objects do not get proxied for perf
      }
      return Reflect.get(target, prop);
    },
    set(target: any, prop: string | symbol, value): boolean {
      if (typeof prop === 'symbol') {
        throw new Error('Setting symbols not allowed.');
      }
      if (Array.isArray(target)) {
        return Reflect.set(target, prop, value);
      }
      if (observers.has(target)) {
        const hosts = observers.get(target);
        hosts?.forEach((elements) => {
          elements.forEach((callbacks: any) => {
            callbacks.forEach((callback: any) => {
              callback(prop, value);
            });
          });
        });
      }
      return Reflect.set(target, prop, value);
    }
  });
}

export const Mutation = {
  fill: 'fill',
  pop: 'pop',
  push: 'push',
  reverse: 'reverse',
  shift: 'shift',
  sort: 'sort',
  splice: 'splice',
  unshift: 'unshift',
  swap: 'swap',
};
